import React, { useEffect, useRef } from 'react';
import { Container, Row, Col } from 'react-bootstrap';

import "../styles/ParallaxImages.css"

const Parallax = ({ images, scrollPercentage }) => {
    const imageRefs = useRef([]);

    useEffect(() => {
        const handleScroll = () => {
            images.forEach((image, index) => {
                const element = imageRefs.current[index];
                if (element) {
                    const displacement = (scrollPercentage / 100) * window.innerWidth;
                    element.style.transform = `translateX(${(displacement * image.imgSpeed) + image.imgOffset}px)`;
                }
            });
        };

        document.addEventListener('scroll', handleScroll);

        return () => {
            document.removeEventListener('scroll', handleScroll);
        };
    }, [images, scrollPercentage]);

    return (
        <Container fluid>
            <Row className="position-relative" style={{ height: '100vh', overflow: 'hidden' }}>
                {images.map((image, index) => (
                    <Col
                        key={index}
                        className={`position-absolute top-0 start-0 layer${index} ${image.repeatX ? 'repeat-x' : ''}`}
                        ref={el => imageRefs.current[index] = el}
                    >
                        <img
                            src={image.imgSrc}
                            alt=""
                            className="img-fluid"
                        />
                    </Col>
                ))}
            </Row>
        </Container>
    );
};

export default Parallax;
